function: async () => {
  await new Promise(r => setTimeout(r, 6000));
  document.querySelector('button[data-target="model-stats"]').click();
  await new Promise(r => setTimeout(r, 2500)); // let color poll finish
  const tabColors = [...document.querySelectorAll('#nav-model-stats [data-source]')].map(t => ({
    src: t.dataset.source,
    color: [...t.classList].filter(c => c.startsWith('server-')).join(',') || '(none)'
  }));
  // open R46 Codex (mom, green with bars)
  document.querySelector('#nav-model-stats [data-source="r46-codex"]').click();
  await new Promise(r => setTimeout(r, 2500));
  const body = document.getElementById('model-stats-body');
  return {
    tabColors,
    r46codex: {
      heading: body.querySelector('h3')?.textContent,
      model: body.querySelector('code')?.textContent,
      windows: [...body.querySelectorAll('.ms-window-head')].map(h => h.textContent),
      bars: [...body.querySelectorAll('.ms-bar-fill')].map(b => b.style.width),
    }
  };
}

function: async () => {
  document.querySelector('#nav-model-stats [data-source="r46-codex"]').click();
  await new Promise(r => setTimeout(r, 7000)); // SSH + HTTPS round-trip
  const body = document.getElementById('model-stats-body');
  const r46codexTab = document.querySelector('#nav-model-stats [data-source="r46-codex"]');
  return {
    heading: body.querySelector('h3')?.textContent,
    model: body.querySelector('code')?.textContent,
    windows: [...body.querySelectorAll('.ms-window-head')].map(h => h.textContent),
    bars: [...body.querySelectorAll('.ms-bar-fill')].map(b => b.style.width + ' ' + b.style.background),
    tabColor: [...r46codexTab.classList].filter(c => c.startsWith('server-')).join(','),
  };
}

function: async () => {
  await new Promise(r => setTimeout(r, 6000));
  document.querySelector('button[data-target="model-stats"]').click();
  await new Promise(r => setTimeout(r, 2500));
  document.querySelector('#nav-model-stats [data-source="w11-codex"]').click();
  await new Promise(r => setTimeout(r, 2000));
  const body = document.getElementById('model-stats-body');
  const tab = document.querySelector('#nav-model-stats [data-source="w11-codex"]');
  return {
    tabColor: [...tab.classList].filter(c => c.startsWith('server-')).join(','),
    windows: [...body.querySelectorAll('.ms-window-head')].map(h => h.textContent),
    bars: [...body.querySelectorAll('.ms-bar-fill')].map(b => b.style.width + ' ' + b.style.background),
    maxedMsg: body.querySelector('.am-warn')?.textContent,
  };
}

function: () => {
  const tr = document.querySelector('#rol-finance-reports-overview tr[data-report-key="bank-6285-pdf2"]');
  return tr ? { found: true, key: tr.dataset.reportKey, html: tr.outerHTML } : { found: false };
}

function: () => {
  const tr = document.querySelector('#rol-finance-reports-overview tr[data-report-key="bank-6285-pdf2"]');
  tr.click();
  const overview = document.getElementById('rol-finance-reports-overview');
  const target = document.getElementById('rol-finance-report-bank-6285-pdf2');
  return {
    overviewActive: overview.classList.contains('active'),
    targetExists: !!target,
    targetActive: target ? target.classList.contains('active') : null,
  };
}

function: () => {
  const dot = document.querySelector('#model-stats-body h3 span');
  const tab = document.querySelector('[data-nav="model-stats"][data-source="w11-claude"]');
  return {
    dotColor: dot ? dot.style.color : null,
    tabClasses: tab ? tab.className : null,
  };
}
